/**
 * Emlog 专属极简图片预览组件 (替代原 Highslide JS)
 * 为 Emlog 量身制作，支持多张图片快速预览、手势操作、缩放旋转与缩略图导航。
 * 
 * @author Antigravity
 * @version 1.0.0
 */
(function() {
    // 缓存 DOM 节点与运行时状态
    let viewerEl = null;
    let imgEl = null;
    let spinnerEl = null;
    let counterEl = null;
    let titleEl = null;
    let thumbsContainer = null;
    
    let items = [];
    let currentIndex = 0;
    let zoomLevel = 1;
    let rotation = 0;
    let isFullscreen = false;
    
    let touchStartX = 0;
    let touchEndX = 0;

    /**
     * 初始化图片查看器的 HTML 结构和事件监听
     */
    function initViewer() {
        if (viewerEl) return;
        
        // 动态创建并插入容器 DOM 结构
        viewerEl = document.createElement('div');
        viewerEl.className = 'em-viewer-overlay';
        viewerEl.innerHTML = `
            <div class="em-viewer-header">
                <div class="em-viewer-counter"></div>
                <div class="em-viewer-title"></div>
                <div class="em-viewer-controls">
                    <button class="em-viewer-btn em-btn-zoom-in" title="放大">
                        <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" stroke-width="2.2" fill="none"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line><line x1="11" y1="8" x2="11" y2="14"></line><line x1="8" y1="11" x2="14" y2="11"></line></svg>
                    </button>
                    <button class="em-viewer-btn em-btn-zoom-out" title="缩小">
                        <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" stroke-width="2.2" fill="none"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line><line x1="11" y1="8" x2="11" y2="14"></line><line x1="8" y1="11" x2="14" y2="11"></line></svg>
                    </button>
                    <button class="em-viewer-btn em-btn-rotate" title="旋转">
                        <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" stroke-width="2.2" fill="none"><path d="M21.5 2v6h-6M21.34 15.57a10 10 0 1 1-.57-8.38l5.67-5.67"></path></svg>
                    </button>
                    <button class="em-viewer-btn em-btn-fullscreen" title="全屏">
                        <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" stroke-width="2.2" fill="none"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"></path></svg>
                    </button>
                    <button class="em-viewer-btn em-btn-close" title="关闭 (Esc)">
                        <svg viewBox="0 0 24 24" width="22" height="22" stroke="currentColor" stroke-width="2.2" fill="none"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                    </button>
                </div>
            </div>
            <div class="em-viewer-body">
                <button class="em-viewer-nav em-btn-prev" title="上一张 (←)">
                    <svg viewBox="0 0 24 24" width="30" height="30" stroke="currentColor" stroke-width="2.5" fill="none"><polyline points="15 18 9 12 15 6"></polyline></svg>
                </button>
                <div class="em-viewer-img-container">
                    <img class="em-viewer-img" src="" alt="预览图片" />
                    <div class="em-viewer-spinner"></div>
                </div>
                <button class="em-viewer-nav em-btn-next" title="下一张 (→)">
                    <svg viewBox="0 0 24 24" width="30" height="30" stroke="currentColor" stroke-width="2.5" fill="none"><polyline points="9 18 15 12 9 6"></polyline></svg>
                </button>
            </div>
            <div class="em-viewer-footer">
                <div class="em-viewer-thumbs"></div>
            </div>
        `;
        
        document.body.appendChild(viewerEl);
        
        // 绑定节点引用
        imgEl = viewerEl.querySelector('.em-viewer-img');
        spinnerEl = viewerEl.querySelector('.em-viewer-spinner');
        counterEl = viewerEl.querySelector('.em-viewer-counter');
        titleEl = viewerEl.querySelector('.em-viewer-title');
        thumbsContainer = viewerEl.querySelector('.em-viewer-thumbs');
        
        // 挂载按钮监听事件
        viewerEl.querySelector('.em-btn-close').addEventListener('click', closeViewer);
        viewerEl.querySelector('.em-btn-zoom-in').addEventListener('click', () => adjustZoom(0.25));
        viewerEl.querySelector('.em-btn-zoom-out').addEventListener('click', () => adjustZoom(-0.25));
        viewerEl.querySelector('.em-btn-rotate').addEventListener('click', rotateImage);
        viewerEl.querySelector('.em-btn-fullscreen').addEventListener('click', toggleFullscreen);
        
        viewerEl.querySelector('.em-btn-prev').addEventListener('click', showPrev);
        viewerEl.querySelector('.em-btn-next').addEventListener('click', showNext);
        
        // 点击背景遮罩关闭查看器
        viewerEl.querySelector('.em-viewer-img-container').addEventListener('click', function(e) {
            if (e.target === this) {
                closeViewer();
            }
        });
        
        // 绑定键盘按键事件
        document.addEventListener('keydown', handleKeydown);
        
        // 绑定移动端手势划动事件
        imgEl.addEventListener('touchstart', handleTouchStart, { passive: true });
        imgEl.addEventListener('touchend', handleTouchEnd, { passive: true });
        
        // 大图加载完毕后处理显示与隐藏 loading 特效
        imgEl.addEventListener('load', function() {
            spinnerEl.style.display = 'none';
            this.classList.add('loaded');
        });
    }

    /**
     * 收集当前页面所有的 class="highslide" 图片项
     * @param {HTMLElement} activeElement 当前被点击的 A 标签元素
     */
    function collectItems(activeElement) {
        const anchors = Array.from(document.querySelectorAll('a.highslide'));
        items = anchors.map((a) => {
            const img = a.querySelector('img');
            // 如果超链接内无 img，表示是列表模式，缩略图降级使用大图链接本身
            const thumbSrc = img ? img.src : a.href;
            
            // 尝试获取合理的图片标题
            let title = a.innerText.trim();
            if (!title && img) {
                title = img.getAttribute('alt') || img.getAttribute('title');
            }
            if (!title) {
                title = a.href.substring(a.href.lastIndexOf('/') + 1);
            }
            
            return {
                href: a.href,
                thumb: thumbSrc,
                title: title,
                el: a
            };
        });
        
        // 匹配当前激活的元素索引
        currentIndex = items.findIndex(item => item.el === activeElement);
        if (currentIndex === -1) {
            currentIndex = 0;
        }
    }

    /**
     * 渲染底部缩略图列表
     */
    function renderThumbs() {
        thumbsContainer.innerHTML = '';
        items.forEach((item, index) => {
            const thumb = document.createElement('img');
            thumb.className = `em-viewer-thumb-item ${index === currentIndex ? 'active' : ''}`;
            thumb.src = item.thumb;
            thumb.alt = item.title;
            thumb.addEventListener('click', () => {
                if (index !== currentIndex) {
                    goToIndex(index);
                }
            });
            thumbsContainer.appendChild(thumb);
        });
        
        // 默认让当前缩略图滚动到视口中央
        scrollActiveThumbIntoView();
    }

    /**
     * 让高亮的缩略图在底部容器中居中显示
     */
    function scrollActiveThumbIntoView() {
        const activeThumb = thumbsContainer.querySelector('.em-viewer-thumb-item.active');
        if (activeThumb) {
            thumbsContainer.scrollLeft = activeThumb.offsetLeft - (thumbsContainer.offsetWidth / 2) + (activeThumb.offsetWidth / 2);
        }
    }

    /**
     * 跳转展示指定索引的图片
     * @param {number} index 图片的索引位置
     */
    function goToIndex(index) {
        if (index < 0 || index >= items.length) return;
        
        currentIndex = index;
        const item = items[currentIndex];
        
        // 重置图片的缩放级别和旋转角度
        zoomLevel = 1;
        rotation = 0;
        updateImgTransform();
        
        // 触发过渡动画，重置状态并加载大图
        spinnerEl.style.display = 'block';
        imgEl.classList.remove('loaded');
        imgEl.src = item.href;
        
        // 渲染文案与当前计数
        titleEl.textContent = item.title;
        counterEl.textContent = `${currentIndex + 1} / ${items.length}`;
        
        // 局部更新底部缩略图的 active 样式
        const thumbs = thumbsContainer.querySelectorAll('.em-viewer-thumb-item');
        thumbs.forEach((thumb, idx) => {
            if (idx === currentIndex) {
                thumb.classList.add('active');
            } else {
                thumb.classList.remove('active');
            }
        });
        
        scrollActiveThumbIntoView();
    }

    /**
     * 切换到上一张图片 (支持循环)
     */
    function showPrev() {
        let index = currentIndex - 1;
        if (index < 0) {
            index = items.length - 1;
        }
        goToIndex(index);
    }

    /**
     * 切换到下一张图片 (支持循环)
     */
    function showNext() {
        let index = currentIndex + 1;
        if (index >= items.length) {
            index = 0;
        }
        goToIndex(index);
    }

    /**
     * 微调大图的显示缩放比例
     * @param {number} delta 缩放量变化值
     */
    function adjustZoom(delta) {
        zoomLevel = Math.max(0.25, Math.min(4, zoomLevel + delta));
        updateImgTransform();
    }

    /**
     * 顺时针旋转图片
     */
    function rotateImage() {
        rotation = (rotation + 90) % 360;
        updateImgTransform();
    }

    /**
     * 将当前的缩放和旋转配置应用到图片元素上
     */
    function updateImgTransform() {
        imgEl.style.transform = `scale(${zoomLevel}) rotate(${rotation}deg)`;
    }

    /**
     * 开启/关闭网页全屏预览
     */
    function toggleFullscreen() {
        if (!isFullscreen) {
            if (viewerEl.requestFullscreen) {
                viewerEl.requestFullscreen();
            } else if (viewerEl.webkitRequestFullscreen) {
                viewerEl.webkitRequestFullscreen();
            } else if (viewerEl.msRequestFullscreen) {
                viewerEl.msRequestFullscreen();
            }
            isFullscreen = true;
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen();
            } else if (document.webkitExitFullscreen) {
                document.webkitExitFullscreen();
            } else if (document.msExitFullscreen) {
                document.msExitFullscreen();
            }
            isFullscreen = false;
        }
    }

    /**
     * 关闭图片预览弹窗
     */
    function closeViewer() {
        if (!viewerEl) return;
        viewerEl.style.opacity = '0';
        setTimeout(() => {
            viewerEl.style.display = 'none';
            if (isFullscreen) {
                toggleFullscreen();
            }
        }, 300);
    }

    /**
     * 处理键盘方向键与 Esc 关闭行为
     * @param {KeyboardEvent} e 键盘事件
     */
    function handleKeydown(e) {
        if (!viewerEl || viewerEl.style.display === 'none') return;
        
        switch (e.key) {
            case 'ArrowLeft':
                showPrev();
                break;
            case 'ArrowRight':
                showNext();
                break;
            case 'Escape':
                closeViewer();
                break;
        }
    }

    /**
     * 触屏手势开始监听
     * @param {TouchEvent} e 触摸事件
     */
    function handleTouchStart(e) {
        touchStartX = e.changedTouches[0].screenX;
    }

    /**
     * 触屏手势结束监听
     * @param {TouchEvent} e 触摸事件
     */
    function handleTouchEnd(e) {
        touchEndX = e.changedTouches[0].screenX;
        handleSwipe();
    }

    /**
     * 根据水平滑动距离判定翻页
     */
    function handleSwipe() {
        const minSwipeDistance = 50; 
        if (touchEndX < touchStartX - minSwipeDistance) {
            showNext();
        } else if (touchEndX > touchStartX + minSwipeDistance) {
            showPrev();
        }
    }

    // 挂载全局 hs 代理对象，向后兼容原 hs.expand 的业务调用
    window.hs = {
        expand: function(element, options) {
            if (window.event) {
                window.event.preventDefault();
            }
            
            // 初始化和渲染 DOM
            initViewer();
            
            // 提取符合 highslide 的全页图片集
            collectItems(element);
            
            // 渲染底部缩略图
            renderThumbs();
            
            // 展示预览容器并淡入
            viewerEl.style.display = 'flex';
            viewerEl.offsetWidth; // 触发重绘以保证动画流畅
            viewerEl.style.opacity = '1';
            
            // 装载并展示当前大图
            goToIndex(currentIndex);
            
            return false;
        }
    };
})();
